document.addEventListener("DOMContentLoaded", function() { fetch("data/site-info.json") .then(response => response.json()) .then(info => { const siteName = document.getElementById("site-name"); if (siteName) siteName.textContent = info.name; const siteTitle = document.getElementById("site-title"); if (siteTitle) siteTitle.textContent = info.title; const heroName = document.getElementById("hero-name"); if (heroName) heroName.textContent = info.name; const heroTitle = document.getElementById("hero-title"); if (heroTitle) heroTitle.textContent = info.title.replace(/\s*\|\s*/g, " \u00b7 "); const caption = document.getElementById("photo-caption"); if (caption) caption.textContent = info.name + " \u00b7 " + new Date().getFullYear(); const metricYears = document.getElementById("metric-years"); if (metricYears) metricYears.setAttribute("data-target", info.metrics.years); const metricProjects = document.getElementById("metric-projects"); if (metricProjects) metricProjects.setAttribute("data-target", info.metrics.projects); const cvLink = document.getElementById("cv-link"); if (cvLink) cvLink.href = info.cv; const linkedinLink = document.getElementById("linkedin-link"); if (linkedinLink) linkedinLink.href = info.social.linkedin; const imdbLink = document.getElementById("imdb-link"); if (imdbLink) imdbLink.href = info.social.imdb; const showreelIframe = document.getElementById("showreel-iframe"); if (showreelIframe) showreelIframe.src = info.youtube.link; const contactEmail = document.getElementById("contact-email"); if (contactEmail) { contactEmail.href = "mailto:" + info.email; contactEmail.textContent = info.email; } const contactLinkedin = document.getElementById("contact-linkedin"); if (contactLinkedin) { contactLinkedin.href = info.social.linkedin; contactLinkedin.textContent = info.social.linkedin .replace("https://www.", "") .replace(/\/$/, ""); } const footerText = document.getElementById("footer-text"); if (footerText) footerText.innerHTML = "&copy; " + info.footer; }) .catch(error => console.error("Site info loading error:", error)); const introScreen = document.getElementById('intro-screen'); const introVideo = document.getElementById('intro-video'); if (introScreen && introVideo) { document.body.classList.add('intro-active'); let introSkipped = false; function endIntro() { if (introSkipped) return; introSkipped = true; introVideo.pause(); introScreen.classList.add('fade-out'); setTimeout(() => { introScreen.style.display = 'none'; document.body.classList.remove('intro-active'); }, 800); } introScreen.addEventListener('click', endIntro); introScreen.addEventListener('touchstart', endIntro, { passive: true }); introVideo.addEventListener('ended', () => { setTimeout(endIntro, 300); }); introVideo.play().catch(() => { endIntro(); }); } const menuToggle = document.createElement('div'); menuToggle.classList.add('menu-toggle'); menuToggle.innerHTML = ` <span></span> <span></span> <span></span> `; const header = document.querySelector('.site-header'); const headerNav = document.querySelector('.header-right'); if (header && headerNav) { header.appendChild(menuToggle); function openMenu() { menuToggle.classList.add('active'); headerNav.classList.add('active'); if (window.innerWidth < 768) { document.body.style.overflow = 'hidden'; } } function closeMenu() { menuToggle.classList.remove('active'); headerNav.classList.remove('active'); document.body.style.overflow = ''; } menuToggle.addEventListener('click', function() { if (!headerNav.classList.contains('active')) { openMenu(); } else { closeMenu(); } }); const navLinks = headerNav.querySelectorAll('a'); navLinks.forEach(link => { link.addEventListener('click', function() { closeMenu(); }); }); document.addEventListener('click', function(e) { if (!header.contains(e.target) && headerNav.classList.contains('active')) { closeMenu(); } }); } fetch("data/skills.json") .then(response => response.json()) .then(skills => { const grid = document.getElementById("skills-grid"); if (!grid) return; skills.forEach(skill => { const item = document.createElement("a"); item.classList.add("skill-item"); if (skill.link) { item.href = skill.link; item.target = "_blank"; item.rel = "noopener noreferrer"; } item.innerHTML = ` <img src="${skill.image}" alt="${skill.name}" loading="lazy"> <span>${skill.name}</span> `; grid.appendChild(item); }); }) .catch(error => console.error("Skills loading error:", error)); fetch("data/projects.json") .then(response => response.json()) .then(projects => { const grid = document.querySelector(".projects-grid"); if (!grid) return; projects.forEach(project => { const card = document.createElement("div"); card.classList.add("project-card"); let statusClass = ''; let statusDot = ''; if (project.status.toLowerCase().includes('production')) { statusClass = 'status-production'; statusDot = '<span class="status-dot status-production"></span>'; } else if (project.status.toLowerCase().includes('released')) { statusClass = 'status-released'; statusDot = '<span class="status-dot status-released"></span>'; } card.innerHTML = ` <div class="project-image"> ${project.kind ? `<span class="project-kind">${project.kind}</span>` : ''} <img src="${project.image}" alt="${project.title}" loading="lazy"> ${project.video ? ` <video class="project-video" muted loop playsinline preload="none"> <source src="${project.video}" type="video/mp4"> </video> ` : ''} </div> <div class="project-info"> <h3>${project.title}</h3> <p class="role-description"> <strong>${project.role}</strong> · ${project.description} </p> <div class="studio-status"> <span>${project.studio}</span> <span class="status">${statusDot}${project.status}</span> </div> </div> `; if (project.video) { const videoElement = card.querySelector('.project-video'); if (videoElement) { card.addEventListener('mouseenter', () => { videoElement.play().catch(err => console.log('Video play failed:', err)); }); card.addEventListener('mouseleave', () => { videoElement.pause(); videoElement.currentTime = 0; }); } } if (project.link) { card.style.cursor = 'pointer'; card.addEventListener('click', () => { window.open(project.link, '_blank'); }); } grid.appendChild(card); }); }) .catch(error => console.error("Projects loading error:", error)); fetch('data/career.json') .then(res => res.json()) .then(career => { const container = document.querySelector('.career-grid'); if(!container) return; career.forEach(c => { const card = document.createElement('div'); card.classList.add('career-card'); const isCurrent = c.period.toLowerCase().includes('present'); card.innerHTML = ` ${c.logo ? `<img src="${c.logo}" alt="${c.studio}" loading="lazy">` : ''} <h3>${c.studio}</h3> <span class="career-role">${c.role}</span> <div class="career-info-container"> <span class="career-period">${c.period}</span> ${c.kind ? `<span class="career-kind">${c.kind}</span>` : ''} </div> ${isCurrent ? '<span class="current-badge"><span class="current-dot"></span>Current</span>' : ''} `; if (c.link) { card.style.cursor = 'pointer'; card.addEventListener('click', () => { window.open(c.link, '_blank'); }); } container.appendChild(card); }); }) .catch(err => console.error("Error loading career:", err)); fetch("data/teaching.json") .then(response => response.json()) .then(teaching => { const container = document.querySelector(".teaching-grid"); if (!container) return; teaching.forEach(t => { const card = document.createElement("div"); card.classList.add("teaching-card"); const isCurrent = t.period.toLowerCase().includes('present'); card.innerHTML = ` ${t.image ? `<img src="${t.image}" alt="${t.title}" loading="lazy">` : ''} <h3>${t.title}</h3> ${t.role ? `<span class="teaching-role">${t.role}</span>` : ''} <div class="teaching-info-container"> <span class="teaching-period">${t.period}</span> ${t.location ? `<span class="teaching-location">${t.location}</span>` : ''} </div> ${isCurrent ? '<span class="current-badge"><span class="current-dot"></span>Current</span>' : ''} `; if (t.link) { card.style.cursor = "pointer"; card.addEventListener("click", () => { window.open(t.link, "_blank"); }); } container.appendChild(card); }); }) .catch(error => console.error("Teaching loading error:", error)); fetch("data/all-personal-work.json") .then(response => response.json()) .then(projects => { const container = document.querySelector(".personal-work-grid"); if (!container) return; const displayProjects = projects.slice(0, 3); displayProjects.forEach((project, index) => { const card = document.createElement("div"); card.classList.add("personal-card"); card.innerHTML = ` <div class="personal-image"> <img src="${project.image}" alt="${project.title}" loading="lazy"> <div class="view-project">VIEW PROJECT</div> </div> <div class="personal-content"> <span class="project-index"> ${String(index + 1).padStart(2, "0")} </span> <h3>${project.title}</h3> ${project.subtitle ? `<h4>${project.subtitle}</h4>` : ''} <p>${project.description}</p> </div> `; card.style.cursor = "pointer"; card.addEventListener("click", () => { window.location.href = `projects/${project.id}.html`; }); container.appendChild(card); }); const btnWrapper = document.createElement("div"); btnWrapper.classList.add("view-all-btn-wrapper"); const viewAllBtn = document.createElement("a"); viewAllBtn.href = "personal-projects.html"; viewAllBtn.classList.add("view-all-projects-btn"); viewAllBtn.innerHTML = `View All Projects <span class="arrow">→</span>`; btnWrapper.appendChild(viewAllBtn); const personalWorkSection = document.getElementById("personal-work"); if (personalWorkSection) { personalWorkSection.appendChild(btnWrapper); } }) .catch(error => console.error("Personal projects loading error:", error)); const metricNumbers = document.querySelectorAll('.metric-number[data-target]'); function scrambleCounter(element) { const target = parseInt(element.dataset.target); const valueSpan = element.querySelector('.metric-value'); if (!valueSpan || element.dataset.animated === 'true') return; element.dataset.animated = 'true'; const duration = 1000; const scrambleSpeed = 50; const startTime = Date.now(); const interval = setInterval(() => { const elapsed = Date.now() - startTime; const progress = Math.min(elapsed / duration, 1); if (progress < 1) { const maxRange = Math.max(1, Math.ceil(9 * (1 - progress))); const randomNum = Math.floor(Math.random() * maxRange) + Math.max(0, target - Math.ceil(maxRange / 2)); valueSpan.textContent = Math.max(0, randomNum); } else { clearInterval(interval); valueSpan.textContent = target; } }, scrambleSpeed); } const metricsObserver = new IntersectionObserver((entries) => { entries.forEach(entry => { if (entry.isIntersecting) { const metrics = entry.target.querySelectorAll('.metric-number[data-target]'); metrics.forEach((el, i) => { setTimeout(() => scrambleCounter(el), i * 200); }); metricsObserver.unobserve(entry.target); } }); }, { threshold: 0.5 }); const metricsContainer = document.querySelector('.about-metrics'); if (metricsContainer) { metricsObserver.observe(metricsContainer); } document.querySelectorAll('a[href^="#"]').forEach(anchor => { anchor.addEventListener('click', function (e) { e.preventDefault(); const target = document.querySelector(this.getAttribute('href')); if (target) { const headerHeight = document.querySelector('.site-header').offsetHeight; const targetPosition = target.getBoundingClientRect().top + window.pageYOffset - headerHeight; window.scrollTo({ top: targetPosition, behavior: 'smooth' }); } }); }); let lastScroll = 0; const heroSection = document.querySelector('.hero'); const scrollToTopBtn = document.getElementById('scroll-to-top'); const aboutSection = document.getElementById('about'); window.addEventListener('scroll', () => { const currentScroll = window.pageYOffset; const siteHeader = document.querySelector('.site-header'); if (currentScroll > 100) { siteHeader.style.background = 'rgba(15, 15, 15, 0.98)'; } else { siteHeader.style.background = 'rgba(15, 15, 15, 0.95)'; } if (heroSection) { if (currentScroll > 400) { heroSection.classList.add('scrolled'); } else { heroSection.classList.remove('scrolled'); } } if (scrollToTopBtn && aboutSection) { const aboutTop = aboutSection.offsetTop; if (currentScroll >= aboutTop) { scrollToTopBtn.classList.add('visible'); } else { scrollToTopBtn.classList.remove('visible'); } } lastScroll = currentScroll; }); if (scrollToTopBtn) { scrollToTopBtn.addEventListener('click', () => { window.scrollTo({ top: 0, behavior: 'smooth' }); }); } const contactForm = document.getElementById('contactForm'); if (contactForm) { contactForm.addEventListener('submit', function (e) { e.preventDefault(); const submitBtn = document.getElementById('contactSubmitBtn'); const successMsg = document.getElementById('contactSuccess'); const errorMsg = document.getElementById('contactError'); const btnText = submitBtn.querySelector('span'); successMsg.style.display = 'none'; errorMsg.style.display = 'none'; btnText.textContent = 'Sending...'; submitBtn.disabled = true; const formData = new FormData(contactForm); fetch('https://api.web3forms.com/submit', { method: 'POST', body: formData }) .then(function (res) { return res.json(); }) .then(function (data) { if (data.success) { successMsg.style.display = 'block'; contactForm.reset(); } else { errorMsg.style.display = 'block'; } }) .catch(function () { errorMsg.style.display = 'block'; }) .finally(function () { btnText.textContent = 'Send Message'; submitBtn.disabled = false; }); }); } function initMobileCarousels() { if (window.innerWidth >= 768) return; const grids = document.querySelectorAll('.projects-grid, .career-grid, .teaching-grid, .personal-work-grid'); grids.forEach(function(grid) { const cards = grid.children; if (cards.length < 2) return; const dotsContainer = document.createElement('div'); dotsContainer.classList.add('carousel-dots'); for (let i = 0; i < cards.length; i++) { const dot = document.createElement('span'); dot.classList.add('dot'); if (i === 0) dot.classList.add('active'); dot.addEventListener('click', function() { const cardWidth = cards[0].offsetWidth + 16; grid.scrollTo({ left: cardWidth * i, behavior: 'smooth' }); }); dotsContainer.appendChild(dot); } grid.parentNode.insertBefore(dotsContainer, grid.nextSibling); let scrollTimeout; grid.addEventListener('scroll', function() { clearTimeout(scrollTimeout); scrollTimeout = setTimeout(function() { const cardWidth = cards[0].offsetWidth + 16; const activeIndex = Math.round(grid.scrollLeft / cardWidth); const dots = dotsContainer.querySelectorAll('.dot'); dots.forEach(function(d, idx) { d.classList.toggle('active', idx === activeIndex); }); }, 50); }); let autoScrollInterval; let userInteracted = false; let resumeTimeout; function startAutoScroll() { autoScrollInterval = setInterval(function() { if (userInteracted) return; const cardWidth = cards[0].offsetWidth + 16; const maxScroll = grid.scrollWidth - grid.clientWidth; if (grid.scrollLeft >= maxScroll - 10) { grid.scrollTo({ left: 0, behavior: 'smooth' }); } else { grid.scrollBy({ left: cardWidth, behavior: 'smooth' }); } }, 4000); } function pauseAutoScroll() { userInteracted = true; clearTimeout(resumeTimeout); resumeTimeout = setTimeout(function() { userInteracted = false; }, 8000); } grid.addEventListener('touchstart', pauseAutoScroll, { passive: true }); grid.addEventListener('mousedown', pauseAutoScroll); startAutoScroll(); grid._autoScrollInterval = autoScrollInterval; grid._dotsContainer = dotsContainer; }); } setTimeout(initMobileCarousels, 1500); });